export const saveCardRequest = (request) => {
  const existing = getCardRequests();
  const newReq   = { ...request, id: Date.now(), status: 'Pending' };
  existing.push(newReq);
  localStorage.setItem('lib_card_requests', JSON.stringify(existing));
  return newReq;
};

/** Update card request status */
export const updateRequestStatus = (id, status) => {
  const requests = getCardRequests();
  const updated  = requests.map(r => r.id === id ? { ...r, status } : r);
  localStorage.setItem('lib_card_requests', JSON.stringify(updated));
